mapper.select:
SELECT id, user_id, balance, create_time, update_time
FROM account
WHERE user_id = #{userId}

mapper.update:
UPDATE account
SET balance = balance + #{amount}, update_time = NOW()
WHERE user_id = #{userId}

UPDATE account
SET balance = balance - #{amount}, update_time = NOW()
WHERE user_id = #{userId} AND balance >= #{amount}
